SELECT COUNT(1)
FROM ai_predict_result
WHERE device_id = #{deviceId}

    AND predict_type = #{predictType}


    AND prediction_time >= #{start}


    AND prediction_time <= #{end}

SELECT id, device_id AS deviceId, predict_type AS predictType,
       prediction_time AS predictionTime, result_json AS resultJson, created_at AS createdAt
FROM ai_predict_result
WHERE device_id = #{deviceId}

    AND predict_type = #{predictType}


    AND prediction_time >= #{start}


    AND prediction_time <= #{end}

ORDER BY prediction_time

    ASC
    DESC

LIMIT #{limit} OFFSET #{offset}
